import { AethelredClient, Job } from '@aethelred/sdk';

const client = new AethelredClient({ endpoint: 'http://localhost:26657' });

const job = await client.submitJob({
  model: 'credit-scoring-v1',
  input: encryptedData,
  compliance: ['GDPR', 'CCPA'],
});

const result = await job.waitForCompletion();
const seal = await client.getSeal(result.sealId);
console.log('Verified:', seal.verify());
